impl std::error::Error for DownloadError {}

/// Calculates the total file size for a batch of downloads using wrapping addition
/// for performance. This uses wrapping_add to avoid panic on overflow in release mode,
/// but also checks for overflow explicitly to report errors.
pub fn calculate_batch_size(file_sizes: &[u64]) -> Result<BatchDownloadInfo, DownloadError> {
    if file_sizes.is_empty() {
        return Err(DownloadError::EmptyFileList);
    }

    let mut total_size: u64 = 0;
    let mut largest_file: u64 = 0;
    let mut smallest_file: u64 = u64::MAX;

    for &size in file_sizes {
        let new_total = total_size.wrapping_add(size);
        // Detect overflow: if the new total is less than the previous total, we overflowed
        if new_total < total_size {
            return Err(DownloadError::Overflow);
        }
        total_size = new_total;

        if size > largest_file {
            largest_file = size;
        }
        if size < smallest_file {
            smallest_file = size;
        }
    }

    let average_size = total_size / file_sizes.len() as u64;

    Ok(BatchDownloadInfo {
        total_size,
        file_count: file_sizes.len(),
        largest_file,
        smallest_file,
        average_size,
    })
}

/// Checks if there is enough available disk space for the batch download.
/// Returns the BatchDownloadInfo if space is sufficient, or an error otherwise.
pub fn check_disk_space_for_batch(
    file_sizes: &[u64],
    available_disk_space: u64,
) -> Result<BatchDownloadInfo, DownloadError> {
    let info = calculate_batch_size(file_sizes)?;

    if info.total_size > available_disk_space {
        return Err(DownloadError::InsufficientDiskSpace {
            required: info.total_size,
            available: available_disk_space,
        });
    }

    Ok(info)
}

/// A faster version that only calculates the total using wrapping_add for maximum performance.
/// Suitable when you only need the total and want minimal overhead.
pub fn calculate_total_size_fast(file_sizes: &[u64]) -> u64 {
    file_sizes
        .iter()
        .fold(0u64, |acc, &size| acc.wrapping_add(size))
}

/// Calculates total with a safety margin (e.g., for temporary files, metadata, etc.)
pub fn calculate_total_with_margin(
    file_sizes: &[u64],
    margin_percent: f64,
) -> Result<u64, DownloadError> {
    let info = calculate_batch_size(file_sizes)?;
    let margin = (info.total_size as f64 * margin_percent / 100.0) as u64;
    let total_with_margin = info.total_size.wrapping_add(margin);
    if total_with_margin < info.total_size {
        return Err(DownloadError::Overflow);
    }
    Ok(total_with_margin)
}

